@namespace sv_53eafb03fbee4efe82ec50754c792d50.Components.Pages.Chat

<div class="channel-sidebar">
    <h3 class="sidebar-header">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name"># @channel.Name</div>
                <div class="channel-description">@TruncateDescription(channel.Description)</div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int SelectedChannelId { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

.channel-sidebar {
    height: 100%;
    background-color: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

.sidebar-header {
    padding: 1rem;
    margin: 0;
    font-size: 1.1rem;
    border-bottom: 1px solid #3d3f56;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    padding: 0.75rem 1rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    position: relative;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: #3d3f56;
}

.channel-item.active {
    background-color: #3d3f56;
    border-left-color: #8d99ae;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-description {
    font-size: 0.75rem;
    color: #8d99ae;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 0.75rem;
    right: 0.75rem;
    background-color: #ef233c;
    color: white;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

