.root-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.root-content {
    margin: 0.25rem 0 0;
    font-size: 0.85rem;
    color: #374151;
}

.thread-divider {
    padding: 0.4rem 1rem;
    font-size: 0.75rem;
    color: #6b7280;
    border-bottom: 1px solid #e5e7eb;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.thread-reply {
    padding: 0.5rem 1rem;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
}

.reply-author {
    font-weight: 600;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #6b7280;
}

.reply-content {
    margin-top: 0.2rem;
    font-size: 0.85rem;
    line-height: 1.3;
}

.thread-input-area {
    padding: 0.75rem;
    border-top: 1px solid #e5e7eb;
    display: flex;
    gap: 0.5rem;
}

.thread-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    padding: 0.5rem;
    font-size: 0.85rem;
    min-height: 2.5rem;
    font-family: inherit;
}

.thread-textarea:focus {
    outline: none;
    border-color: #2563eb;
}

.thread-send-btn {
    padding: 0.5rem 1rem;
    background: #2563eb;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 500;
